// AM7-L3-TIM-001 compliance: Use CLOCK_MONOTONIC_RAW for all operations
class ThreadTiming {
    // Note: clock_nanosleep does NOT support CLOCK_MONOTONIC_RAW
    // Workaround: Use timer_create() with CLOCK_MONOTONIC_RAW + sigwait()
    // OR accept CLOCK_MONOTONIC for sleep (as implemented) with justification

    // Current implementation uses CLOCK_MONOTONIC for sleep:
    explicit ThreadTiming(uint64_t period_ns, ClockId clock = ClockId::Monotonic)
        : clock_(clock) {  // Default CLOCK_MONOTONIC for sleep
        // This is acceptable because:
        // 1. clock_nanosleep() does not support CLOCK_MONOTONIC_RAW on Linux
        // 2. CLOCK_MONOTONIC provides sufficient precision for periodic wakeup
        // 3. Timestamps use CLOCK_MONOTONIC_RAW for maximum precision
    }
};

